// Get the incoming JSON data
const data = $json.data?.response?.sunoData || [];

// Extract all song audio URLs
const songUris = data.map(item => ({
  title: item.title,
  audioUrl: item.audioUrl,
  sourceAudioUrl: item.sourceAudioUrl,
  imageUrl: item.imageUrl,
}));

// Return as items for next node
return songUris.map(uri => ({ json: uri }));

// Sanitize + format YouTube tags for n8n YouTube node
// - Produces BOTH: tagsArray (array) and tagsCsv (comma-separated string)
// - Bind the YouTube node's "Tags" field to {{$json.tagsCsv}}

try {
  const item = $json;

  const toArr = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v !== 'string') return [];
    // Split on commas, newlines, or '#'
    return v.split(/[,#\n]/g).map(s => s.trim()).filter(Boolean);
  };

  const candidates = [
    ...toArr(item.tags),
    ...toArr(item['Video Tags']),
    ...toArr(item.seo_keywords),
  ];

  const cleanOne = (t) => {
    // strip emoji/pictographs
    let s = t.replace(/[\p{Extended_Pictographic}\u{2600}-\u{27BF}]/gu, '');
    // keep letters/numbers/spaces/&/+/ - /'
    s = s.replace(/[^\p{L}\p{N}\s&+\-']/gu, '');
    // collapse spaces
    s = s.replace(/\s+/g, ' ').trim();
    return s;
  };

  // normalize, dedupe (case-insensitive), per-tag length 2–30 chars
  const seen = new Set();
  const normalized = [];
  for (const raw of candidates) {
    const c = cleanOne(raw);
    if (!c || c.length < 2 || c.length > 30) continue;
    const key = c.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    normalized.push(c);
  }

  // total budget (~500 incl commas); be safe at 450; also cap count
  const finalTags = [];
  let used = 0;
  for (const tag of normalized) {
    const addLen = (finalTags.length ? 2 : 0) + tag.length; // ', ' between tags
    if (used + addLen > 450) break;
    finalTags.push(tag);
    used += addLen;
    if (finalTags.length >= 25) break;
  }

  const tagsArray = finalTags;
  const tagsCsv = finalTags.join(', '); // <- use this in the YouTube node

  return [{ json: { ...item, tagsArray, tagsCsv } }];
} catch (e) {
  return [{
    json: { ...$json, tagsArray: [], tagsCsv: '', tagSanitizerError: e?.message || 'unknown_error' }
  }];
}

